    <script>
        // ============================================================
        // COIN HERO — 3D Animated Challenge Coin (Canvas 2D)
        // ============================================================

        const heroCanvas = document.getElementById('coin-hero');
        const ctx = heroCanvas.getContext('2d');

        let animationId;
        let isPaused = false;
        let currentTime = 0;
        const LOOP_DURATION = 8000; // ms for full loop

        function resizeHero() {
            const rect = heroCanvas.getBoundingClientRect();
            const dpr = window.devicePixelRatio || 1;
            heroCanvas.width = rect.width * dpr;
            heroCanvas.height = rect.height * dpr;
            ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
        }

        resizeHero();
        window.addEventListener('resize', resizeHero);

        // Coin parameters
        const COIN_RADIUS = 140;
        const COIN_THICKNESS = 12;
        const REED_COUNT = 60;

        function drawCoin(ctx, width, height, time) {
            ctx.clearRect(0, 0, width, height);

            const cx = width / 2;
            const cy = height / 2;

            // Rotation angles
            const verticalAngle = (time % LOOP_DURATION) / LOOP_DURATION * Math.PI * 2;
            const horizontalAngle = Math.sin((time % LOOP_DURATION) / LOOP_DURATION * Math.PI * 2) * Math.PI;

            // Project to 2D
            const cosV = Math.cos(verticalAngle);
            const sinV = Math.sin(verticalAngle);
            const cosH = Math.cos(horizontalAngle);
            const sinH = Math.sin(horizontalAngle);

            // Effective width (foreshortening from vertical rotation)
            const effectiveWidth = COIN_RADIUS * Math.abs(cosV);
            const effectiveHeight = COIN_RADIUS;

            // Determine which face is visible
            const frontFacing = cosH > 0;

            // Draw reeded edge
            drawReededEdge(ctx, cx, cy, effectiveWidth, effectiveHeight, verticalAngle, horizontalAngle, cosV, sinV, cosH, sinH);

            // Draw coin face
            if (frontFacing) {
                drawFrontFace(ctx, cx, cy, effectiveWidth, effectiveHeight, verticalAngle, horizontalAngle);
            } else {
                drawBackFace(ctx, cx, cy, effectiveWidth, effectiveHeight, verticalAngle, horizontalAngle);
            }

            // Draw edge thickness
            drawEdgeThickness(ctx, cx, cy, effectiveWidth, effectiveHeight, verticalAngle, horizontalAngle, cosV, sinV, cosH, sinH);

            // Apply specular highlight
            applySpecularHighlight(ctx, cx, cy, effectiveWidth, effectiveHeight, verticalAngle, horizontalAngle, time);
        }

        function drawReededEdge(ctx, cx, cy, ew, eh, vAngle, hAngle, cosV, sinV, cosH, sinH) {
            ctx.save();

            const edgePoints = [];
            for (let i = 0; i < REED_COUNT; i++) {
                const angle = (i / REED_COUNT) * Math.PI * 2;
                const x3d = COIN_RADIUS * Math.cos(angle);
                const y3d = COIN_RADIUS * Math.sin(angle);
                const z3d = COIN_THICKNESS / 2;

                // Apply rotations
                let px = x3d * cosV - z3d * sinV;
                let py = y3d;
                let pz = x3d * sinV + z3d * cosV;

                // Horizontal flip rotation
                const hcos = Math.cos(hAngle);
                const hsin = Math.sin(hAngle);
                let px2 = px;
                let py2 = py * hcos - pz * hsin;
                let pz2 = py * hsin + pz * hcos;

                // Project
                const scale = 800 / (800 + pz2);
                const sx = cx + px2 * scale;
                const sy = cy + py2 * scale;

                edgePoints.push({ x: sx, y: sy, z: pz2, scale: scale });
            }

            // Draw reeds on visible portion
            for (let i = 0; i < REED_COUNT; i++) {
                const p1 = edgePoints[i];
                const p2 = edgePoints[(i + 1) % REED_COUNT];

                // Only draw if roughly in front or side
                if (p1.z > -5 && p2.z > -5) {
                    const reedHeight = 3 * p1.scale;
                    const avgScale = (p1.scale + p2.scale) / 2;

                    ctx.beginPath();
                    ctx.moveTo(p1.x, p1.y);
                    ctx.lineTo(p2.x, p2.y);
                    ctx.strokeStyle = `rgba(${150 + Math.random() * 30}, ${140 + Math.random() * 20}, ${100 + Math.random() * 20}, ${0.3 + avgScale * 0.3})`;
                    ctx.lineWidth = reedHeight;
                    ctx.stroke();
                }
            }

            ctx.restore();
        }

        function drawFrontFace(ctx, cx, cy, ew, eh, vAngle, hAngle) {
            ctx.save();

            // Main face ellipse
            const gradient = ctx.createRadialGradient(cx - ew * 0.3, cy - eh * 0.3, 0, cx, cy, Math.max(ew, eh));
            gradient.addColorStop(0, '#d4a855');
            gradient.addColorStop(0.3, '#b8923f');
            gradient.addColorStop(0.6, '#8a6828');
            gradient.addColorStop(1, '#5a4218');

            ctx.beginPath();
            ctx.ellipse(cx, cy, ew, eh, 0, 0, Math.PI * 2);
            ctx.fillStyle = gradient;
            ctx.fill();

            // Inner ring
            const innerScale = 0.85;
            ctx.beginPath();
            ctx.ellipse(cx, cy, ew * innerScale, eh * innerScale, 0, 0, Math.PI * 2);
            ctx.strokeStyle = 'rgba(60, 40, 15, 0.6)';
            ctx.lineWidth = 3;
            ctx.stroke();

            // Emblem - WastedToken logo
            drawEmblem(ctx, cx, cy, ew * 0.6, eh * 0.6);

            // Text around edge
            drawEdgeText(ctx, cx, cy, ew * 0.92, eh * 0.92, 'WASTED TOKEN MINT • EST. 2024 • ');

            ctx.restore();
        }

        function drawBackFace(ctx, cx, cy, ew, eh, vAngle, hAngle) {
            ctx.save();

            // Main face ellipse - slightly different tone for back
            const gradient = ctx.createRadialGradient(cx - ew * 0.3, cy - eh * 0.3, 0, cx, cy, Math.max(ew, eh));
            gradient.addColorStop(0, '#c8a045');
            gradient.addColorStop(0.3, '#a88835');
            gradient.addColorStop(0.6, '#7a5e25');
            gradient.addColorStop(1, '#4a3515');

            ctx.beginPath();
            ctx.ellipse(cx, cy, ew, eh, 0, 0, Math.PI * 2);
            ctx.fillStyle = gradient;
            ctx.fill();

            // Inner ring
            const innerScale = 0.85;
            ctx.beginPath();
            ctx.ellipse(cx, cy, ew * innerScale, eh * innerScale, 0, 0, Math.PI * 2);
            ctx.strokeStyle = 'rgba(60, 40, 15, 0.6)';
            ctx.lineWidth = 3;
            ctx.stroke();

            // Denomination text
            drawDenomination(ctx, cx, cy, ew * 0.7, eh * 0.7);

            // Decorative elements
            drawDecorativeStars(ctx, cx, cy, ew * 0.92, eh * 0.92);

            ctx.restore();
        }

        function drawEmblem(ctx, cx, cy, size) {
            ctx.save();

            // Shield shape
            const shieldW = size * 0.8;
            const shieldH = size * 1.1;

            ctx.beginPath();
            ctx.moveTo(cx, cy - shieldH);
            ctx.quadraticCurveTo(cx + shieldW, cy - shieldH * 0.5, cx + shieldW * 0.7, cy + shieldH * 0.2);
            ctx.quadraticCurveTo(cx + shieldW * 0.4, cy + shieldH * 0.6, cx, cy + shieldH * 0.8);
            ctx.quadraticCurveTo(cx - shieldW * 0.4, cy + shieldH * 0.6, cx - shieldW * 0.7, cy + shieldH * 0.2);
            ctx.quadraticCurveTo(cx - shieldW, cy - shieldH * 0.5, cx, cy - shieldH);
            ctx.closePath();

            // Raised relief effect
            const reliefGrad = ctx.createLinearGradient(cx - shieldW, cy - shieldH, cx + shieldW, cy + shieldH);
            reliefGrad.addColorStop(0, '#e8c878');
            reliefGrad.addColorStop(0.5, '#d4a855');
            reliefGrad.addColorStop(1, '#b8923f');

            ctx.fillStyle = reliefGrad;
            ctx.fill();
            ctx.strokeStyle = 'rgba(60, 40, 15, 0.8)';
            ctx.lineWidth = 2;
            ctx.stroke();

            // WT letters inside shield
            ctx.font = `bold ${size * 0.7}px Georgia`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';
            ctx.fillStyle = '#3a2810';
            ctx.fillText('WT', cx, cy);

            // Star above shield
            drawStar(ctx, cx, cy - shieldH * 1.2, size * 0.25, 5);

            ctx.restore();
        }

        function drawDenomination(ctx, cx, cy, size) {
            ctx.save();

            // Large denomination number
            ctx.font = `bold ${size * 1.2}px Georgia`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            // Shadow for depth
            ctx.fillStyle = 'rgba(40, 25, 10, 0.6)';
            ctx.fillText('10,000', cx + 2, cy - size * 0.3 + 2);

            // Main text with metallic gradient
            const textGrad = ctx.createLinearGradient(cx - size, cy - size, cx + size, cy + size);
            textGrad.addColorStop(0, '#f0d890');
            textGrad.addColorStop(0.5, '#d4a855');
            textGrad.addColorStop(1, '#b8923f');

            ctx.fillStyle = textGrad;
            ctx.fillText('10,000', cx, cy - size * 0.3);

            // "TOKENS" below
            ctx.font = `bold ${size * 0.45}px Georgia`;
            ctx.fillStyle = '#3a2810';
            ctx.fillText('TOKENS', cx, cy + size * 0.3);

            // Decorative lines
            const lineY = cy - size * 0.1;
            ctx.beginPath();
            ctx.moveTo(cx - size * 0.6, lineY);
            ctx.lineTo(cx + size * 0.6, lineY);
            ctx.strokeStyle = 'rgba(60, 40, 15, 0.5)';
            ctx.lineWidth = 2;
            ctx.stroke();

            ctx.restore();
        }

        function drawEdgeText(ctx, cx, cy, ew, eh, text) {
            ctx.save();
            ctx.font = `${Math.max(8, ew * 0.1)}px Georgia`;
            ctx.textAlign = 'center';
            ctx.textBaseline = 'middle';

            const steps = 40;
            for (let i = 0; i < steps; i++) {
                const angle = (i / steps) * Math.PI * 2;
                const x = cx + ew * Math.cos(angle);
                const y = cy + eh * Math.sin(angle);

                ctx.save();
                ctx.translate(x, y);
                ctx.rotate(angle + Math.PI / 2);
                ctx.fillStyle = 'rgba(60, 40, 15, 0.7)';
                ctx.fillText(text, 0, 0);
                ctx.restore();
            }

            ctx.restore();
        }

        function drawDecorativeStars(ctx, cx, cy, ew, eh) {
            ctx.save();
            const starCount = 6;
            for (let i = 0; i < starCount; i++) {
                const angle = (i / starCount) * Math.PI * 2 - Math.PI / 2;
                const x = cx + ew * 0.75 * Math.cos(angle);
                const y = cy + eh * 0.75 * Math.sin(angle);
                drawStar(ctx, x, y, ew * 0.08, 5);
            }
            ctx.restore();
        }

        function drawStar(ctx, x, y, size, points) {
            ctx.save();
            ctx.beginPath();
            for (let i = 0; i < points * 2; i++) {
                const radius = i % 2 === 0 ? size : size * 0.4;
                const angle = (i / (points * 2)) * Math.PI * 2 - Math.PI / 2;
                const px = x + radius * Math.cos(angle);
                const py = y + radius * Math.sin(angle);
                if (i === 0) ctx.moveTo(px, py);
                else ctx.lineTo(px, py);
            }
            ctx.closePath();
            ctx.fillStyle = '#3a2810';
            ctx.fill();
            ctx.restore();
        }

        function drawEdgeThickness(ctx, cx, cy, ew, eh, vAngle, hAngle, cosV, sinV, cosH, sinH) {
            ctx.save();

            // Draw the visible edge as a curved surface
            const edgeGradient = ctx.createLinearGradient(cx - ew, cy, cx + ew, cy);
            edgeGradient.addColorStop(0, 'rgba(80, 60, 30, 0.8)');
            edgeGradient.addColorStop(0.5, 'rgba(120, 90, 40, 0.6)');
            edgeGradient.addColorStop(1, 'rgba(80, 60, 30, 0.8)');

            ctx.beginPath();
            ctx.ellipse(cx, cy, ew, eh, 0, 0, Math.PI * 2);
            ctx.strokeStyle = edgeGradient;
            ctx.lineWidth = COIN_THICKNESS * Math.abs(cosV) * 0.5;
            ctx.stroke();

            ctx.restore();
        }

        function applySpecularHighlight(ctx, cx, cy, ew, eh, vAngle, hAngle, time) {
            ctx.save();

            // Specular highlight position based on rotation
            const specX = cx + ew * 0.4 * Math.cos(vAngle + time * 0.001);
            const specY = cy - eh * 0.3 * Math.sin(vAngle) + eh * 0.2 * Math.cos(hAngle);

            // Create radial gradient for highlight
            const highlightGrad = ctx.createRadialGradient(specX, specY, 0, specX, specY, ew * 0.5);
            highlightGrad.addColorStop(0, 'rgba(255, 255, 240, 0.6)');
            highlightGrad.addColorStop(0.3, 'rgba(255, 255, 240, 0.3)');
            highlightGrad.addColorStop(0.7, 'rgba(255, 255, 240, 0.1)');
            highlightGrad.addColorStop(1, 'rgba(255, 255, 240, 0)');

            ctx.beginPath();
            ctx.ellipse(cx, cy, ew, eh, 0, 0, Math.PI * 2);
            ctx.clip();
            ctx.fillStyle = highlightGrad;
            ctx.fillRect(0, 0, ctx.canvas.width, ctx.canvas.height);

            // Secondary highlight
            const spec2X = cx - ew * 0.3 * Math.cos(vAngle + Math.PI);
            const spec2Y = cy + eh * 0.4 * Math.sin(hAngle);
            const highlightGrad2 = ctx.createRadialGradient(spec2X, spec2Y, 0, spec2X, spec2Y, ew * 0.3);
            highlightGrad2.addColorStop(0, 'rgba(255, 255, 240, 0.3)');
            highlightGrad2.addColorStop(1, 'rgba(255, 255, 240, 0)');

            ctx.fillStyle = highlightGrad2;
            ctx.fillRect(0, 0, ctx.canvas.width, ctx.canvas.height);

            ctx.restore();
        }

        // Animation loop
        let lastTime = 0;

        function animate(timestamp) {
            if (!isPaused) {
                currentTime += timestamp - lastTime;
                lastTime = timestamp;

                const width = heroCanvas.width / (window.devicePixelRatio || 1);
                const height = heroCanvas.height / (window.devicePixelRatio || 1);

                drawCoin(ctx, width, height, currentTime);
            } else {
                lastTime = timestamp;
            }

            animationId = requestAnimationFrame(animate);
        }

        // Start animation
        lastTime = performance.now();
        animationId = requestAnimationFrame(animate);

        // ============================================================
        // EDITION CANVASES — Procedurally rendered mini coins
        // ============================================================

        function drawEditionCoin(canvas, edition) {
            const dpr = window.devicePixelRatio || 1;
            const size = 180;
            canvas.width = size * dpr;
            canvas.height = size * dpr;
            canvas.style.width = size + 'px';
            canvas.style.height = size + 'px';

            const ectx = canvas.getContext('2d');
            ectx.setTransform(dpr, 0, 0, dpr, 0, 0);

            const cx = size / 2;
            const cy = size / 2;
            const radius = size * 0.42;

            // Determine color scheme based on edition
            let colors;
            switch (edition) {
                case 'bronze':
                    colors = {
                        base: ['#d4a855', '#b8923f', '#8a6828', '#5a4218'],
                        highlight: 'rgba(255, 255, 240, 0.4)',
                        text: '#3a2810'
                    };
                    break;
                case 'silver':
                    colors = {
                        base: ['#e8e8e8', '#c0c0c0', '#909090', '#606060'],
                        highlight: 'rgba(255, 255, 255, 0.5)',
                        text: '#303030'
                    };
                    break;
                case 'gold':
                    colors = {
                        base: ['#ffd700', '#ffed4e', '#daa520', '#b8860b'],
                        highlight: 'rgba(255, 255, 240, 0.5)',
                        text: '#4a3515'
                    };
                    break;
                case 'black':
                    colors = {
                        base: ['#2a2a2a', '#1a1a1a', '#0a0a0a', '#000000'],
                        highlight: 'rgba(100, 150, 255, 0.3)',
                        text: '#4a4a6a'
                    };
                    break;
            }

            // Main coin body
            const gradient = ectx.createRadialGradient(cx - radius * 0.3, cy - radius * 0.3, 0, cx, cy, radius);
            colors.base.forEach((color, i) => {
                gradient.addColorStop(i / (colors.base.length - 1), color);
            });

            ectx.beginPath();
            ectx.arc(cx, cy, radius, 0, Math.PI * 2);
            ectx.fillStyle = gradient;
            ectx.fill();

            // Inner ring
            ectx.beginPath();
            ectx.arc(cx, cy, radius * 0.85, 0, Math.PI * 2);
            ectx.strokeStyle = colors.text + '99';
            ectx.lineWidth = 2;
            ectx.stroke();

            // Emblem/text
            if (edition === 'gold') {
                ectx.font = `bold ${radius * 0.5}px Georgia`;
                ectx.textAlign = 'center';
                ectx.textBaseline = 'middle';
                ectx.fillStyle = colors.text;
                ectx.fillText('10K', cx, cy - radius * 0.2);
                ectx.font = `${radius * 0.2}px Georgia`;
                ectx.fillText('TOKENS', cx, cy + radius * 0.3);
            } else if (edition === 'black') {
                // Circuit pattern for obsidian
                ectx.strokeStyle = '#4a6a9a';
                ectx.lineWidth = 1;
                for (let i = 0; i < 8; i++) {
                    const angle = (i / 8) * Math.PI * 2;
                    const x1 = cx + radius * 0.3 * Math.cos(angle);
                    const y1 = cy + radius * 0.3 * Math.sin(angle);
                    const x2 = cx + radius * 0.7 * Math.cos(angle);
                    const y2 = cy + radius * 0.7 * Math.sin(angle);
                    ectx.beginPath();
                    ectx.moveTo(x1, y1);
                    ectx.lineTo(x2, y2);
                    ectx.stroke();
                }
                // Center dot
                ectx.beginPath();
                ectx.arc(cx, cy, radius * 0.15, 0, Math.PI * 2);
                ectx.fillStyle = '#4a6a9a';
                ectx.fill();
            } else {
                // WT emblem for bronze/silver
                ectx.font = `bold ${radius * 0.6}px Georgia`;
                ectx.textAlign = 'center';
                ectx.textBaseline = 'middle';
                ectx.fillStyle = colors.text;
                ectx.fillText('WT', cx, cy);
            }

            // Specular highlight
            const specGrad = ectx.createRadialGradient(cx - radius * 0.3, cy - radius * 0.3, 0, cx, cy, radius * 0.6);
            specGrad.addColorStop(0, colors.highlight);
            specGrad.addColorStop(1, 'rgba(0,0,0,0)');

            ectx.beginPath();
            ectx.arc(cx, cy, radius, 0, Math.PI * 2);
            ectx.clip();
            ectx.fillStyle = specGrad;
            ectx.fillRect(0, 0, size, size);

            // Edge highlight
            ectx.beginPath();
            ectx.arc(cx, cy, radius, 0, Math.PI * 2);
            ectx.strokeStyle = 'rgba(255,255,255,0.1)';
            ectx.lineWidth = 3;
            ectx.stroke();
        }

        // Initialize edition canvases
        document.querySelectorAll('.edition-canvas').forEach(canvas => {
            const edition = canvas.closest('.edition').dataset.edition;
            drawEditionCoin(canvas, edition);
        });

        // ============================================================
        // PROGRAMMATIC API — Required for grading
        // ============================================================

        window.demo = {
            canvas: heroCanvas,

            setTime(t) {
                // t in [0,1] -> render exactly that point of the loop
                const width = heroCanvas.width / (window.devicePixelRatio || 1);
                const height = heroCanvas.height / (window.devicePixelRatio || 1);

                // Map t to time within loop duration
                currentTime = t * LOOP_DURATION;

                drawCoin(ctx, width, height, currentTime);
            },

            pause() {
                isPaused = true;
                if (animationId) {
                    cancelAnimationFrame(animationId);
                }
            }
        };
    </script>
